import sys
class Solution:
    def longestSpecialPath(self, edges, nums):
        sys.setrecursionlimit(10000)
        n = len(nums)
        adj = [[] for _ in range(n)]
        for u, v, w in edges:
            adj[u].append((v, w))
            adj[v].append((u, w))
        children = [[] for _ in range(n)]
        visited = [False] * n
        visited[0] = True
        stack = [0]
        while stack:
            node = stack.pop()
            for nxt, w in adj[node]:
                if not visited[nxt]:
                    visited[nxt] = True
                    children[node].append((nxt, w))
                    stack.append(nxt)
        best_len = 0
        best_nodes = 1

        def dfs_recursive(node, seen, dist, cnt):
            nonlocal best_len, best_nodes
            if dist > best_len or (dist == best_len and cnt < best_nodes):
                best_len = dist
                best_nodes = cnt
            for nxt, w in children[node]:
                if nums[nxt] in seen:
                    continue
                seen.add(nums[nxt])
                dfs_recursive(nxt, seen, dist + w, cnt + 1)
                seen.discard(nums[nxt])

        for a in range(n):
            dfs_recursive(a, {nums[a]}, 0, 1)
        return [best_len, best_nodes]

