var longestSpecialPath = function(edges, nums) {
    const n = nums.length;
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
        adj[v].push([u, w]);
    }
    const children = Array.from({ length: n }, () => []);
    const visited = new Array(n).fill(false);
    visited[0] = true;
    const stack = [0];
    while (stack.length) {
        const node = stack.pop();
        for (const [nxt, w] of adj[node]) {
            if (!visited[nxt]) {
                visited[nxt] = true;
                children[node].push([nxt, w]);
                stack.push(nxt);
            }
        }
    }
    let bestLen = 0;
    let bestNodes = 1;
    function dfs(node, seen, dist, cnt) {
        if (dist > bestLen || (dist === bestLen && cnt < bestNodes)) {
            bestLen = dist;
            bestNodes = cnt;
        }
        for (const [nxt, w] of children[node]) {
            if (seen.has(nums[nxt])) continue;
            seen.add(nums[nxt]);
            dfs(nxt, seen, dist + w, cnt + 1);
            seen.delete(nums[nxt]);
        }
    }
    for (let a = 0; a < n; a++) {
        dfs(a, new Set([nums[a]]), 0, 1);
    }
    return [bestLen, bestNodes];
};
